<?php
namespace App\Domain\Combat;use App\Domain\Combat\Data\CombatCommand;use App\Domain\Combat\Data\CombatResult;use App\Domain\Combat\Data\CombatRound;use App\Domain\Combat\Data\CombatState;use App\Domain\Combat\Data\CombatantStats;
final class CombatSimulator {const MAX_ROUNDS=100;private $resolver;public function __construct(CombatActionResolver $resolver){$this->resolver=$resolver;}public function simulate(CombatantStats $character,CombatantStats $monster):CombatResult{$first=$character->attackSpeed()>=$monster->attackSpeed()?$character->identifier():$monster->identifier();$ch=$character->currentHealth();$mh=$monster->currentHealth();if($ch===0||$mh===0){if($ch===0&&$mh===0)$status=CombatResultStatus::DRAW;elseif($ch===0)$status=CombatResultStatus::MONSTER_VICTORY;else$status=CombatResultStatus::CHARACTER_VICTORY;$state=new CombatState($character,$monster,$ch,$mh,0,$first,null,$status);return $this->result($state,[]);}$state=new CombatState($character,$monster,$ch,$mh,1,$first,$first,CombatStateStatus::IN_PROGRESS);$rounds=[];for($round=1;$round<=self::MAX_ROUNDS&&$state->status()===CombatStateStatus::IN_PROGRESS;$round++){$actions=[];while($state->status()===CombatStateStatus::IN_PROGRESS&&$state->roundNumber()===$round){$actor=$state->nextActorIdentifier();$target=$actor===$character->identifier()?$monster->identifier():$character->identifier();$step=$this->resolver->resolve($state,new CombatCommand(null,$actor,CombatActionType::BASIC_ATTACK,$target));$actions[]=$step->resolvedAction();$state=$step->nextState();}$rounds[]=new CombatRound($round,$actions);}if($state->status()===CombatStateStatus::IN_PROGRESS)$state=new CombatState($character,$monster,$state->characterCurrentHealth(),$state->monsterCurrentHealth(),$state->roundNumber(),$state->firstActorIdentifier(),null,CombatResultStatus::DRAW);return$this->result($state,$rounds);}private function result(CombatState $state,array $rounds){$winner=null;if($state->status()===CombatResultStatus::CHARACTER_VICTORY)$winner=$state->character()->identifier();elseif($state->status()===CombatResultStatus::MONSTER_VICTORY)$winner=$state->monster()->identifier();return new CombatResult($state->status(),$winner,count($rounds),$state->character()->currentHealth(),$state->characterCurrentHealth(),$state->monster()->currentHealth(),$state->monsterCurrentHealth(),$rounds);}}
